    if (req.session.userId) {
        statusMessage += `<p>Currently logged in as user: <strong>${req.session.userId}</strong></p>`;
        if (req.session.twoFactorPassed) {
            statusMessage += `<p>2FA Status: <strong style="color: green;">Passed!</strong> <a href="/dashboard">Go to Dashboard</a></p>`;
        } else {
            statusMessage += `<p>2FA Status: <strong style="color: orange;">Pending!</strong> <a href="/generate-2fa">Complete 2FA</a></p>`;
        }
        statusMessage += `<p><a href="/logout">Logout</a></p>`;
    } else {
        statusMessage = '<p><a href="/login-as-user">Simulate Login (User ID: 123)</a></p>';
    }

    res.send(`
        <h1>Welcome to the 2FA System Demo</h1>
        <p>This demonstrates a Node.js Express two-factor authentication system using SMS codes.</p>
        ${statusMessage}
    `);
